// Helper function to split a string by a delimiter into a vector
std::vector<std::string> split(const std::string &str, char delim) {
    std::vector<std::string> tokens;
    std::stringstream ss(str);
    std::string token;
    while (getline(ss, token, delim)) {
        tokens.push_back(token);
    }
    return tokens;
}

// Function to parse each student entry and add to the roster
void parseAndAddStudentData(Roster& roster, const std::string& studentData) {
    std::vector<std::string> data = split(studentData, ',');

    // Assuming the data is always correctly formatted
    std::string studentID = data.at(0);
    std::string firstName = data.at(1);
    std::string lastName = data.at(2);
    std::string email = data.at(3);
    int age = std::stoi(data.at(4));
    int daysInCourse1 = std::stoi(data.at(5));
    int daysInCourse2 = std::stoi(data.at(6));
    int daysInCourse3 = std::stoi(data.at(7));
    DegreeProgram degreeProgram;

    // Map the string to DegreeProgram enum
    if (data.at(8) == "SECURITY") {
        degreeProgram = DegreeProgram::SECURITY;
    } else if (data.at(8) == "NETWORK") {
        degreeProgram = DegreeProgram::NETWORK;
    } else if (data.at(8) == "SOFTWARE") {
        degreeProgram = DegreeProgram::SOFTWARE;
    }

    // Add the student to the roster
    roster.add(studentID, firstName, lastName, email, age,
               daysInCourse1, daysInCourse2, daysInCourse3, degreeProgram);
}

// Main function
int main() {
    // ...
    Roster classRoster;

    // Loop through all student entries in the array and parse them
    for (const std::string& entry : studentData) {
        parseAndAddStudentData(classRoster, entry);
    }

    // ... (other function calls)

    // Clean up resources
    // ...

    return 0;
}
```

